import{_ as e,o as a,c as t,U as r}from"./chunks/framework.8ac43607.js";const _=JSON.parse('{"title":"改动日志","description":"","frontmatter":{},"headers":[],"relativePath":"blogs/2023/03/changelog.md","filePath":"blogs/2023/03/changelog.md","lastUpdated":1683265338000}'),o={name:"blogs/2023/03/changelog.md"},n=r('<h1 id="改动日志" tabindex="-1">改动日志 <a class="header-anchor" href="#改动日志" aria-label="Permalink to &quot;改动日志&quot;">​</a></h1><ul><li><a href="./semver.html">语义化版本</a></li><li><a href="./conventional-commits.html">约定式提交</a></li><li>改动日志 - 本篇</li></ul><p>改动日志反馈了每个版本的改动，它没有固定的格式，常常提供给使用者阅读。</p><h2 id="关联" tabindex="-1">关联 <a class="header-anchor" href="#关联" aria-label="Permalink to &quot;关联&quot;">​</a></h2><h3 id="和语义化版本的关联" tabindex="-1">和语义化版本的关联 <a class="header-anchor" href="#和语义化版本的关联" aria-label="Permalink to &quot;和语义化版本的关联&quot;">​</a></h3><p>习惯上，我们推荐一份改动日志对应一个版本，并将所有改动日志放到一个文件内（一般是 <code>CHANGELOG.md</code>）。</p><p>即便你没有使用语义化版本，也有必要提供改动日志。改动日志能更详细地告知使用者具体的改动内容，这往往是某些使用者特别关注的。另外，改动日志也可以作为开发者的备忘录之一，给开发者带来便利（比如我 😅）。</p><h3 id="和约定式提交的关联" tabindex="-1">和约定式提交的关联 <a class="header-anchor" href="#和约定式提交的关联" aria-label="Permalink to &quot;和约定式提交的关联&quot;">​</a></h3><p>每一个约定式提交的描述和正文，可以作为一条改动日志列写在改动日志文件内。</p><p>类似地，你也可以使用工具自动生成改动日志！这又一步地节省了不少时间，不是吗？</p><h2 id="改动日志的思考" tabindex="-1">改动日志的思考 <a class="header-anchor" href="#改动日志的思考" aria-label="Permalink to &quot;改动日志的思考&quot;">​</a></h2><p><a href="https://keepachangelog.com/zh-CN/" target="_blank" rel="noreferrer">keepachangelog</a> 提出了一个观点：<code>更新日志绝对不应该是 git 日志的堆砌物</code>。</p><p>我认为它反映了约定式提交的缺陷，而不是改动日志本身的缺陷。约定式提交是主观的，一旦约定式提交不能准确地描述提交的 <strong>意图</strong>，或者约定式提交不够 <strong>整洁</strong>，借助工具和 git 日志生成的改动日志就很有可能带来迷惑性。反过来，如果我们规范了约定式提交，那么自动生成的改动日志可读性就会很高。</p><p><code>keepachangelog</code> 还提出，改动日志文件内应该要有 <code>Unreleased</code> 章节来记录准备发布的更新内容。这样可以帮助部分使用者了解未来可能会有什么变更，降低迁移成本。</p><p>就我个人而言，我认为只维护一个改动日志文件对于大部分情况足够，但仍然有所不足，尤其是功能复杂的情况时。<a href="https://tailwindcss.com/" target="_blank" rel="noreferrer">tailwindcss</a> 是我心中的典范。它是怎么做的呢？每一个 MAJOR 和 MINOR 版本发布，除了会更新更新日志文件外，还会发布一篇 <strong>博文</strong> 来阐述团队的工作。这篇博文简单、明确地描述了 <strong>新功能</strong> 并提供了对应的 <strong>例子</strong>，同时也加入了 <strong>文档链接</strong>，帮助使用者更快地掌握新功能。除此之外，周边生态有更新时，也会发布一篇博文。总体而言，我认为 <code>tailwindcss</code> 是目前我见到的对使用者最友好的库之一。</p><h2 id="实践" tabindex="-1">实践 <a class="header-anchor" href="#实践" aria-label="Permalink to &quot;实践&quot;">​</a></h2><p>有非常多工具支持自动生成改动日志，而且这些工具大部分都依赖于约定式提交。比较老牌的是 <a href="https://github.com/conventional-changelog/conventional-changelog/tree/master/packages/conventional-changelog-cli" target="_blank" rel="noreferrer">conventional-changelog-cli</a> 和 <a href="https://github.com/oscarotero/keep-a-changelog" target="_blank" rel="noreferrer">keep-a-changelog</a>，它们都很不错。</p><p><a href="https://github.com/changesets/changesets" target="_blank" rel="noreferrer">changesets</a> 和 <a href="https://github.com/unjs/changelogen" target="_blank" rel="noreferrer">changelogen</a> 是近几年开始流行的选择，前者更适用于 monorepo，后者我认为还需要一点时间发展。</p><p>如果你想要更一体化的解决方案，包括自动更新版本和自动生成改动日志，你应该查看一下 <a href="https://github.com/absolute-version/commit-and-tag-version" target="_blank" rel="noreferrer">commit-and-tag-version</a> 和 <a href="https://github.com/semantic-release/semantic-release" target="_blank" rel="noreferrer">semantic-release</a>。我就在使用前者。</p><p>本篇是系列的最后一篇，我建议你阅读完 <a href="./semver.html">语义化版本</a>、<a href="./conventional-commits.html">约定式提交</a> 和 改动日志（就是本篇）再开始实践！😄</p>',20),l=[n];function s(c,h,i,g,p,d){return a(),t("div",null,l)}const f=e(o,[["render",s]]);export{_ as __pageData,f as default};
